# Prompt: Using Python: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import os
import io
import time
import hashlib
from datetime import datetime
from flask import Flask, request, jsonify
import boto3
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.chrome.service import Service
from PIL import Image
import uuid

app = Flask(__name__)

AWS_REGION = os.environ.get('AWS_REGION', 'us-east-1')
S3_BUCKET = os.environ.get('S3_BUCKET', 'screenshot-thumbnails')
SCREENSHOT_WIDTH = int(os.environ.get('SCREENSHOT_WIDTH', '1280'))
SCREENSHOT_HEIGHT = int(os.environ.get('SCREENSHOT_HEIGHT', '720'))
THUMBNAIL_WIDTH = int(os.environ.get('THUMBNAIL_WIDTH', '400'))
THUMBNAIL_HEIGHT = int(os.environ.get('THUMBNAIL_HEIGHT', '300'))

s3_client = boto3.client('s3', region_name=AWS_REGION)


def get_chrome_driver():
    chrome_options = Options()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--no-sandbox')
    chrome_options.add_argument('--disable-dev-shm-usage')
    chrome_options.add_argument('--disable-gpu')
    chrome_options.add_argument('--window-size=1280,720')
    chrome_options.add_argument('--disable-software-rasterizer')
    chrome_options.add_argument('--disable-extensions')
    chrome_options.add_argument('--disable-logging')
    chrome_options.add_argument('--log-level=3')
    chrome_options.add_argument('--silent')
    chrome_options.add_argument('--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36')
    
    driver = webdriver.Chrome(options=chrome_options)
    driver.set_page_load_timeout(30)
    
    return driver


def generate_url_hash(url):
    return hashlib.md5(url.encode()).hexdigest()


def capture_screenshot(url):
    driver = None
    try:
        driver = get_chrome_driver()
        driver.get(url)
        time.sleep(2)
        
        screenshot_bytes = driver.get_screenshot_as_png()
        
        return screenshot_bytes
    except Exception as e:
        raise Exception(f"Failed to capture screenshot: {str(e)}")
    finally:
        if driver:
            driver.quit()


def create_thumbnail(screenshot_bytes, width=THUMBNAIL_WIDTH, height=THUMBNAIL_HEIGHT):
    try:
        image = Image.open(io.BytesIO(screenshot_bytes))
        image.thumbnail((width, height), Image.Resampling.LANCZOS)
        
        thumbnail_io = io.BytesIO()
        image.save(thumbnail_io, format='PNG', optimize=True)
        thumbnail_io.seek(0)
        
        return thumbnail_io.getvalue()
    except Exception as e:
        raise Exception(f"Failed to create thumbnail: {str(e)}")


def upload_to_s3(file_bytes, file_name, content_type='image/png'):
    try:
        s3_client.put_object(
            Bucket=S3_BUCKET,
            Key=file_name,
            Body=file_bytes,
            ContentType=content_type,
            ACL='public-read'
        )
        
        url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{file_name}"
        return url
    except Exception as e:
        raise Exception(f"Failed to upload to S3: {str(e)}")


def check_s3_exists(file_name):
    try:
        s3_client.head_object(Bucket=S3_BUCKET, Key=file_name)
        url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{file_name}"
        return url
    except:
        return None


@app.route('/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy'}), 200


@app.route('/screenshot', methods=['POST'])
def screenshot():
    try:
        data = request.get_json()
        
        if not data or 'url' not in data:
            return jsonify({'error': 'URL is required'}), 400
        
        url = data['url']
        force_refresh = data.get('force_refresh', False)
        
        if not url.startswith(('http://', 'https://')):
            url = 'https://' + url
        
        url_hash = generate_url_hash(url)
        timestamp = datetime.now().strftime('%Y%m%d')
        
        full_screenshot_name = f"screenshots/{timestamp}/{url_hash}.png"
        thumbnail_name = f"thumbnails/{timestamp}/{url_hash}.png"
        
        if not force_refresh:
            existing_thumbnail = check_s3_exists(thumbnail_name)
            if existing_thumbnail:
                return jsonify({
                    'success': True,
                    'thumbnail_url': existing_thumbnail,
                    'cached': True
                }), 200
        
        screenshot_bytes = capture_screenshot(url)
        
        thumbnail_bytes = create_thumbnail(screenshot_bytes)
        
        full_screenshot_url = upload_to_s3(screenshot_bytes, full_screenshot_name)
        thumbnail_url = upload_to_s3(thumbnail_bytes, thumbnail_name)
        
        return jsonify({
            'success': True,
            'url': url,
            'thumbnail_url': thumbnail_url,
            'full_screenshot_url': full_screenshot_url,
            'cached': False,
            'timestamp': datetime.now().isoformat()
        }), 200
        
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


@app.route('/screenshot/batch', methods=['POST'])
def batch_screenshot():
    try:
        data = request.get_json()
        
        if not data or 'urls' not in data:
            return jsonify({'error': 'URLs array is required'}), 400
        
        urls = data['urls']
        
        if not isinstance(urls, list):
            return jsonify({'error': 'URLs must be an array'}), 400
        
        if len(urls) > 10:
            return jsonify({'error': 'Maximum 10 URLs per batch'}), 400
        
        results = []
        
        for url in urls:
            try:
                if not url.startswith(('http://', 'https://')):
                    url = 'https://' + url
                
                url_hash = generate_url_hash(url)
                timestamp = datetime.now().strftime('%Y%m%d')
                
                thumbnail_name = f"thumbnails/{timestamp}/{url_hash}.png"
                
                existing_thumbnail = check_s3_exists(thumbnail_name)
                if existing_thumbnail:
                    results.append({
                        'url': url,
                        'success': True,
                        'thumbnail_url': existing_thumbnail,
                        'cached': True
                    })
                    continue
                
                screenshot_bytes = capture_screenshot(url)
                thumbnail_bytes = create_thumbnail(screenshot_bytes)
                thumbnail_url = upload_to_s3(thumbnail_bytes, thumbnail_name)
                
                results.append({
                    'url': url,
                    'success': True,
                    'thumbnail_url': thumbnail_url,
                    'cached': False
                })
                
            except Exception as e:
                results.append({
                    'url': url,
                    'success': False,
                    'error': str(e)
                })
        
        return jsonify({
            'success': True,
            'results': results,
            'total': len(urls),
            'successful': sum(1 for r in results if r['success'])
        }), 200
        
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


@app.route('/screenshot/delete', methods=['DELETE'])
def delete_screenshot():
    try:
        data = request.get_json()
        
        if not data or 'url' not in data:
            return jsonify({'error': 'URL is required'}), 400
        
        url = data['url']
        
        if not url.startswith(('http://', 'https://')):
            url = 'https://' + url
        
        url_hash = generate_url_hash(url)
        timestamp = datetime.now().strftime('%Y%m%d')
        
        thumbnail_name = f"thumbnails/{timestamp}/{url_hash}.png"
        full_screenshot_name = f"screenshots/{timestamp}/{url_hash}.png"
        
        deleted = []
        errors = []
        
        try:
            s3_client.delete_object(Bucket=S3_BUCKET, Key=thumbnail_name)
            deleted.append(thumbnail_name)
        except Exception as e:
            errors.append(f"Thumbnail: {str(e)}")
        
        try:
            s3_client.delete_object(Bucket=S3_BUCKET, Key=full_screenshot_name)
            deleted.append(full_screenshot_name)
        except Exception as e:
            errors.append(f"Full screenshot: {str(e)}")
        
        return jsonify({
            'success': True,
            'deleted': deleted,
            'errors': errors if errors else None
        }), 200
        
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)